   391→              <div className="space-y-4">
   392→                <div>
   393→                  <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mb-2">
   394→                    Selected tags will be replaced with:
   395→                  </p>
   396→                  <div className="flex flex-wrap gap-2 p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded border border-border-light dark:border-border-dark">
   397→                    {Array.from(selectedTags).map((tag) => (
