     1→/**
     2→ * TagPicker Component
     3→ *
     4→ * Inline tag picker with autocomplete for adding tags to notes
     5→ * Features:
     6→ * - Dropdown with existing tags
     7→ * - Create new tags inline
     8→ * - Keyboard navigation
     9→ * - Click-outside-to-close
    10→ */
    11→
    12→import { useState, useRef, useEffect, useMemo } from 'react';
    13→import { X, Plus, Tag as TagIcon, ChevronRight, ChevronDown } from 'lucide-react';
    14→import { useTags, useRecentTags } from '../hooks/useTags';
    15→import { buildTagTree, normalizeTag, type TagNode } from '../utils/tagHierarchy';
    16→
    17→interface TagPickerProps {
    18→  /** Currently selected tags */
    19→  selectedTags: string[];
    20→  /** Callback when tag is added */
    21→  onAddTag: (tag: string) => void;
    22→  /** Callback when tag is removed */
    23→  onRemoveTag: (tag: string) => void;
    24→  /** Maximum number of tags allowed */
    25→  maxTags?: number;
    26→}
    27→
    28→export function TagPicker({ selectedTags, onAddTag, onRemoveTag, maxTags = 20 }: TagPickerProps) {
    29→  const [isOpen, setIsOpen] = useState(false);
    30→  const [searchQuery, setSearchQuery] = useState('');
    31→  const [expandedTags, setExpandedTags] = useState<Set<string>>(new Set());
    32→  const inputRef = useRef<HTMLInputElement>(null);
    33→  const dropdownRef = useRef<HTMLDivElement>(null);
    34→
    35→  // Get all existing tags and recent tags
    36→  const allTags = useTags();
    37→  const recentTags = useRecentTags(5);
    38→
    39→  // Build tag tree from all tags
    40→  const tagTree = useMemo(() => buildTagTree(allTags), [allTags]);
    41→
    42→  // Filter tags based on search query and exclude already selected
    43→  const filteredTags = allTags.filter(
    44→    (tag) =>
    45→      !selectedTags.includes(tag) &&
    46→      tag.toLowerCase().includes(searchQuery.toLowerCase())
    47→  );
    48→
    49→  // Show recent tags if no search query
    50→  const suggestedTags = searchQuery
    51→    ? filteredTags.slice(0, 10)
    52→    : recentTags.filter((tag) => !selectedTags.includes(tag));
    53→
    54→  // Handle click outside to close
    55→  useEffect(() => {
    56→    function handleClickOutside(event: MouseEvent) {
    57→      if (
    58→        dropdownRef.current &&
    59→        !dropdownRef.current.contains(event.target as Node) &&
    60→        inputRef.current &&
    61→        !inputRef.current.contains(event.target as Node)
    62→      ) {
    63→        setIsOpen(false);
    64→        setSearchQuery('');
    65→      }
    66→    }
    67→
    68→    if (isOpen) {
    69→      document.addEventListener('mousedown', handleClickOutside);
    70→      return () => document.removeEventListener('mousedown', handleClickOutside);
    71→    }
    72→  }, [isOpen]);
    73→
    74→  // Focus input when opened
    75→  useEffect(() => {
    76→    if (isOpen && inputRef.current) {
    77→      inputRef.current.focus();
    78→    }
    79→  }, [isOpen]);
    80→
    81→  const handleAddTag = (tag: string) => {
    82→    const normalizedTag = normalizeTag(tag);
    83→    if (!normalizedTag) return;
    84→    if (selectedTags.includes(normalizedTag)) return;
    85→    if (selectedTags.length >= maxTags) return;
    86→
    87→    onAddTag(normalizedTag);
    88→    setSearchQuery('');
    89→    setIsOpen(false);
    90→  };
    91→
    92→  const toggleExpand = (tag: string) => {
    93→    setExpandedTags(prev => {
    94→      const next = new Set(prev);
    95→      if (next.has(tag)) {
    96→        next.delete(tag);
    97→      } else {
    98→        next.add(tag);
    99→      }
   100→      return next;
   101→    });
   102→  };
   103→
   104→  // Recursive function to render tag tree
   105→  const renderTagNode = (node: TagNode): React.ReactNode => {
   106→    const hasChildren = node.children.length > 0;
   107→    const isExpanded = expandedTags.has(node.name);
   108→    const isSelected = selectedTags.includes(node.name);
   109→
   110→    return (
   111→      <div key={node.name}>
   112→        <button
   113→          onClick={() => {
   114→            if (!hasChildren) {
   115→              handleAddTag(node.name);
   116→            }
   117→          }}
   118→          disabled={isSelected}
   119→          className={`
   120→            w-full flex items-center gap-2 px-3 py-1.5 text-sm text-left
   121→            hover:bg-surface-light dark:hover:bg-surface-dark transition-colors
   122→            ${isSelected ? 'opacity-50 cursor-not-allowed' : ''}
   123→          `}
   124→          style={{ paddingLeft: `${node.level * 16 + 12}px` }}
   125→        >
   126→          {hasChildren && (
   127→            <span
   128→              onClick={(e) => {
   129→                e.stopPropagation();
   130→                toggleExpand(node.name);
   131→              }}
   132→              className="flex-shrink-0 cursor-pointer"
   133→            >
   134→              {isExpanded ? (
   135→                <ChevronDown className="w-3 h-3 text-text-light-tertiary dark:text-text-dark-tertiary" />
   136→              ) : (
   137→                <ChevronRight className="w-3 h-3 text-text-light-tertiary dark:text-text-dark-tertiary" />
   138→              )}
   139→            </span>
   140→          )}
   141→          {!hasChildren && <span className="w-3" />}
   142→          <TagIcon className="w-3 h-3 text-accent-purple dark:text-accent-cyan flex-shrink-0" />
   143→          <span className="flex-1 text-text-light-primary dark:text-text-dark-primary truncate">
   144→            {node.label}
   145→          </span>
   146→          {hasChildren && (
   147→            <span className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary flex-shrink-0">
   148→              ({node.children.length})
   149→            </span>
   150→          )}
   151→        </button>
   152→
   153→        {/* Render children if expanded */}
   154→        {hasChildren && isExpanded && (
   155→          <div>
   156→            {node.children.map(child => renderTagNode(child))}
   157→          </div>
   158→        )}
   159→      </div>
   160→    );
   161→  };
   162→
   163→  const handleKeyDown = (e: React.KeyboardEvent) => {
   164→    if (e.key === 'Enter') {
   165→      e.preventDefault();
   166→      if (searchQuery.trim()) {
   167→        handleAddTag(searchQuery);
   168→      } else if (suggestedTags.length > 0) {
   169→        handleAddTag(suggestedTags[0]);
   170→      }
   171→    } else if (e.key === 'Escape') {
   172→      setIsOpen(false);
   173→      setSearchQuery('');
   174→    }
   175→  };
   176→
   177→  const canAddMore = selectedTags.length < maxTags;
   178→
   179→  return (
   180→    <div className="relative">
   181→      {/* Selected Tags Display */}
   182→      <div className="flex flex-wrap gap-2 items-center">
   183→        {selectedTags.map((tag) => (
   184→          <span
   185→            key={tag}
   186→            className="inline-flex items-center gap-1 px-2 py-1 text-xs font-medium rounded bg-accent-purple/10 text-accent-purple dark:bg-accent-cyan/10 dark:text-accent-cyan transition-colors"
   187→          >
   188→            <TagIcon className="w-3 h-3" />
   189→            {tag}
   190→            <button
   191→              onClick={() => onRemoveTag(tag)}
   192→              className="hover:bg-accent-purple/20 dark:hover:bg-accent-cyan/20 rounded p-0.5 transition-colors"
   193→              aria-label={`Remove tag ${tag}`}
   194→            >
   195→              <X className="w-3 h-3" />
   196→            </button>
   197→          </span>
   198→        ))}
   199→
   200→        {/* Add Tag Button */}
   201→        {canAddMore && (
