   108→  // Actions - Pin/Archive/Favorite
   109→  togglePin: (id: string) => void;
   110→  toggleArchive: (id: string) => void;
   111→  toggleFavorite: (id: string) => void;
   112→
   113→  // Actions - Tags
   114→  addTag: (id: string, tag: string) => void;
   115→  removeTag: (id: string, tag: string) => void;
   116→  getAllTags: () => string[];
   117→  getTagUsageCounts: () => Map<string, number>;
   118→  renameTag: (oldTag: string, newTag: string) => void;
   119→  mergeTags: (sourceTags: string[], targetTag: string) => void;
   120→  deleteTag: (tag: string) => void;
   121→  renameTagGlobally: (oldTag: string, newTag: string) => void;
   122→  deleteTagGlobally: (tag: string) => void;
   123→
   124→  // Actions - UI state
   125→  setActiveNote: (id: string | null) => void;
   126→  setSortConfig: (config: NoteSortConfig) => void;
   127→  setFilter: (filter: NoteFilter) => void;
   128→
   129→  // Actions - Utility
   130→  getNoteCount: () => number;
   131→  getNotesInFolder: (folderId: string | null) => Note[];
   132→  exportNotes: () => Note[];
   133→  importNotes: (notes: Note[], merge: boolean) => void;
   134→  clearAllNotes: () => void;
   135→
   136→  // Actions - Backlinks (Phase 4)
   137→  getBacklinks: (noteId: string) => Note[];
   138→  updateLinkedNotes: (noteId: string, content: string) => void;
   139→
   140→  // Actions - Templates (Phase 4)
   141→  getNoteTemplates: () => NoteTemplate[];
   142→  createNoteFromTemplate: (templateId: string) => Note | null;
   143→
   144→  // Actions - Daily Notes
   145→  getDailyNote: (date: Date) => Note | null;
   146→  createDailyNote: (date: Date) => Note;
   147→  getOrCreateDailyNote: (date: Date) => Note;
   148→}
   149→
   150→/**
   151→ * Default note values
   152→ */
   153→const createDefaultNote = (overrides?: Partial<Note>): Note => {
   154→  const now = new Date();
   155→  return {
   156→    id: uuidv4(),
   157→    folderId: null,
   158→    title: NOTE_CONSTANTS.DEFAULT_TITLE,
   159→    content: '', // Empty Lexical state
   160→    contentText: '',
   161→    tags: [],
   162→    createdAt: now,
   163→    updatedAt: now,
   164→    isPinned: false,
   165→    isArchived: false,
   166→    ...overrides,
   167→  };
   168→};
   169→
   170→/**
   171→ * Sort notes based on sort config
   172→ */
   173→const sortNotes = (notes: Note[], config: NoteSortConfig): Note[] => {
   174→  const sorted = [...notes];
   175→
   176→  sorted.sort((a, b) => {
   177→    let comparison = 0;
   178→
   179→    switch (config.field) {
   180→      case 'title':
   181→        comparison = a.title.localeCompare(b.title);
   182→        break;
   183→      case 'createdAt':
   184→        comparison = a.createdAt.getTime() - b.createdAt.getTime();
   185→        break;
   186→      case 'updatedAt':
   187→        comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   188→        break;
   189→      case 'manual':
   190→        // Manual sort - preserve order (could add sortOrder field in future)
   191→        comparison = 0;
   192→        break;
   193→    }
   194→
   195→    return config.order === 'asc' ? comparison : -comparison;
   196→  });
   197→
   198→  // Always pin pinned notes to top
   199→  return sorted.sort((a, b) => {
   200→    if (a.isPinned && !b.isPinned) return -1;
   201→    if (!a.isPinned && b.isPinned) return 1;
   202→    return 0;
   203→  });
   204→};
   205→
   206→/**
   207→ * Filter notes based on filter type
   208→ */
   209→const filterNotes = (notes: Note[], filter: NoteFilter): Note[] => {
   210→  switch (filter) {
   211→    case 'favorites':
   212→      return notes.filter((note) => note.isFavorite);
   213→    case 'pinned':
   214→      return notes.filter((note) => note.isPinned);
   215→    case 'archived':
   216→      return notes.filter((note) => note.isArchived);
   217→    case 'unarchived':
   218→      return notes.filter((note) => !note.isArchived);
   219→    case 'all':
   220→    default:
   221→      return notes;
   222→  }
   223→};
   224→
   225→/**
   226→ * Create the Notes store
   227→ */
   228→export const useNotesStore = create<NotesStore>()(
   229→  persist(
   230→    (set, get) => ({
   231→      // Initial state
   232→      notes: {},
   233→      activeNoteId: null,
   234→      sortConfig: {
   235→        field: 'updatedAt',
   236→        order: 'desc',
   237→      },
   238→      filter: 'unarchived',
   239→
   240→      // CRUD Operations
   241→      createNote: (params) => {
   242→        const newNote = createDefaultNote(params);
   243→        set((state) => ({
   244→          notes: {
   245→            ...state.notes,
   246→            [newNote.id]: newNote,
   247→          },
   248→          activeNoteId: newNote.id, // Auto-select new note
   249→        }));
   250→        log.debug('Note created', { id: newNote.id });
   251→        return newNote;
