  1111→      addDependency: (taskId, dependency) => {
  1112→        // Prevent self-dependency
  1113→        if (taskId === dependency.taskId) {
  1114→          log.error('Task cannot depend on itself', { taskId });
  1115→          return;
  1116→        }
  1117→
  1118→        // Check for circular dependency
  1119→        const task = get().tasks.find(t => t.id === taskId);
  1120→        if (!task) {
  1121→          log.error('Task not found', { taskId });
  1122→          return;
  1123→        }
  1124→
  1125→        const wouldCreateCycle = (currentTaskId: string, blockerTaskId: string, visited = new Set<string>()): boolean => {
  1126→          if (currentTaskId === blockerTaskId) return true;
  1127→          if (visited.has(currentTaskId)) return false; // Already checked
  1128→
  1129→          visited.add(currentTaskId);
  1130→
  1131→          // Get the blocker task's dependencies
  1132→          const blockerTask = get().tasks.find(t => t.id === blockerTaskId);
  1133→          if (!blockerTask || !blockerTask.dependencies) return false;
  1134→
  1135→          // Check if blocker depends on current (directly or indirectly)
  1136→          return blockerTask.dependencies.some(dep => wouldCreateCycle(currentTaskId, dep.taskId, visited));
  1137→        };
  1138→
  1139→        if (wouldCreateCycle(taskId, dependency.taskId)) {
  1140→          log.error('Circular dependency detected', { taskId, dependsOn: dependency.taskId });
  1141→          return;
  1142→        }
  1143→
  1144→        // Add dependency to task
  1145→        set((state) => ({
  1146→          tasks: state.tasks.map(t => {
  1147→            if (t.id === taskId) {
  1148→              const existingDeps = t.dependencies || [];
  1149→              // Check if dependency already exists
  1150→              if (existingDeps.some(d => d.taskId === dependency.taskId)) {
  1151→                log.warn('Dependency already exists', { taskId, dependsOn: dependency.taskId });
  1152→                return t;
  1153→              }
  1154→              return {
  1155→                ...t,
  1156→                dependencies: [...existingDeps, dependency],
  1157→              };
  1158→            }
  1159→            return t;
  1160→          }),
  1161→        }));
  1162→
  1163→        // Log activity with dependency type info
  1164→        const dependencyLabel = {
  1165→          'finish-to-start': 'FS (Finish-to-Start)',
