  1170→
  1171→        const lagLabel = dependency.lag !== 0
  1172→          ? ` with ${dependency.lag > 0 ? '+' : ''}${dependency.lag} day${Math.abs(dependency.lag) !== 1 ? 's' : ''} lag`
  1173→          : '';
  1174→
  1175→        get().logActivity(taskId, {
  1176→          action: 'created',
  1177→          field: 'dependency',
  1178→          newValue: `Depends on task ${dependency.taskId} (${dependencyLabel}${lagLabel})`,
  1179→        });
  1180→      },
  1181→
  1182→      removeDependency: (taskId, dependencyId) => {
  1183→        const task = get().tasks.find(t => t.id === taskId);
