  1192→          return;
  1193→        }
  1194→
  1195→        // Remove dependency from task
  1196→        set((state) => ({
  1197→          tasks: state.tasks.map(t => {
  1198→            if (t.id === taskId) {
  1199→              return {
  1200→                ...t,
  1201→                dependencies: (t.dependencies || []).filter(d => d.taskId !== dependencyId),
  1202→              };
  1203→            }
  1204→            return t;
  1205→          }),
