  1221→      },
  1222→
  1223→      getBlockers: (taskId) => {
  1224→        // Get tasks that this task depends on (blockers)
  1225→        const task = get().tasks.find(t => t.id === taskId);
  1226→        if (!task || !task.dependencies) return [];
  1227→
  1228→        const blockerIds = task.dependencies.map(d => d.taskId);
  1229→        return get().tasks.filter(t => blockerIds.includes(t.id));
  1230→      },
  1231→
  1232→      getBlocked: (taskId) => {
  1233→        // Get tasks that depend on this task (blocked by this task)
  1234→        const allTasks = get().tasks;
  1235→        return allTasks.filter(t =>
  1236→          t.dependencies?.some(d => d.taskId === taskId)
  1237→        );
  1238→      },
  1239→
  1240→      getOverdueBlockers: (taskId) => {
  1241→        // P1: Get blocker tasks that are overdue (for dependency warnings)
  1242→        const blockers = get().getBlockers(taskId);
  1243→        const today = new Date();
  1244→        today.setHours(0, 0, 0, 0); // Start of day
  1245→
  1246→        return blockers.filter(blocker => {
  1247→          // Blocker is overdue if:
  1248→          // 1. It's not done
  1249→          // 2. It has a due date
  1250→          // 3. Due date is before today
  1251→          if (blocker.status === 'done') return false;
  1252→          if (!blocker.dueDate) return false;
  1253→
  1254→          const dueDate = new Date(blocker.dueDate);
  1255→          dueDate.setHours(0, 0, 0, 0);
