     1→/**
     2→ * Custom Fields Type Definitions
     3→ *
     4→ * Defines types for custom field system that allows users to add
     5→ * structured metadata to tasks and notes beyond default fields.
     6→ */
     7→
     8→/**
     9→ * Supported custom field types
    10→ */
    11→export type FieldType =
    12→  | 'text'
    13→  | 'number'
    14→  | 'date'
    15→  | 'select'
    16→  | 'checkbox'
    17→  | 'person'      // P2: Person/user assignment
    18→  | 'status'      // P2: Status with visual indicators
    19→  | 'timeline'    // P2: Date range (start/end)
    20→  | 'formula';    // P2: Calculated fields
    21→
    22→/**
    23→ * Status option configuration for status field type
    24→ */
    25→export interface StatusOption {
    26→  label: string;
    27→  color: string; // Semantic token color (e.g., 'accent-blue', 'accent-green')
    28→}
    29→
    30→/**
    31→ * Timeline value structure
    32→ */
    33→export interface TimelineValue {
    34→  startDate: string; // ISO date string
    35→  endDate: string;   // ISO date string
    36→}
    37→
    38→/**
    39→ * Field definition - describes a custom field's schema
    40→ */
    41→export interface FieldDefinition {
    42→  /** Unique identifier for the field */
    43→  id: string;
    44→  /** Display name of the field */
    45→  name: string;
    46→  /** Field data type */
    47→  type: FieldType;
    48→  /** Default value when field is added to a task/note */
    49→  defaultValue?: any;
    50→  /** For 'select' type: list of allowed options */
    51→  options?: string[];
    52→  /** Whether this field is required */
    53→  required?: boolean;
    54→  /** Optional description/help text */
    55→  description?: string;
    56→  /** Whether field is visible on Kanban cards (default: true) */
    57→  visibleInCard?: boolean;
    58→  /** Whether field is visible in List view (default: true) */
    59→  visibleInList?: boolean;
    60→  /** Timestamp when field was created */
    61→  createdAt: Date;
    62→  /** Timestamp when field was last modified */
    63→  updatedAt: Date;
    64→
    65→  // P2: Advanced field type settings
    66→  /** For 'person' type: allow multiple people */
    67→  allowMultiple?: boolean;
    68→  /** For 'status' type: status options with colors */
    69→  statusOptions?: StatusOption[];
    70→  /** For 'formula' type: formula expression */
    71→  formulaExpression?: string;
    72→  /** For 'formula' type: referenced field IDs */
    73→  referencedFields?: string[];
    74→}
    75→
    76→/**
    77→ * Custom field value instance
    78→ */
    79→export interface CustomFieldValue {
    80→  /** ID of the field definition this value corresponds to */
    81→  fieldId: string;
    82→  /** Actual value (type varies based on field.type) */
    83→  value: any;
    84→}
    85→
    86→/**
    87→ * Map of field values on a task/note
    88→ * Key: fieldId, Value: actual value
    89→ */
    90→export type CustomFieldsMap = Record<string, any>;
    91→
    92→/**
    93→ * Field validation result
    94→ */
    95→export interface FieldValidationResult {
    96→  /** Whether the value is valid for this field type */
    97→  valid: boolean;
    98→  /** Error message if validation failed */
    99→  error?: string;
   100→}
   101→
   102→/**
   103→ * Validates a field value based on field definition
   104→ */
   105→export function validateFieldValue(
   106→  field: FieldDefinition,
   107→  value: any
   108→): FieldValidationResult {
   109→  // Empty values are valid if field is not required
   110→  if (value === null || value === undefined || value === '') {
   111→    if (field.required) {
   112→      return { valid: false, error: 'This field is required' };
   113→    }
   114→    return { valid: true };
   115→  }
   116→
   117→  switch (field.type) {
   118→    case 'text':
   119→      if (typeof value !== 'string') {
   120→        return { valid: false, error: 'Value must be text' };
   121→      }
   122→      return { valid: true };
   123→
   124→    case 'number':
   125→      const num = typeof value === 'string' ? parseFloat(value) : value;
   126→      if (typeof num !== 'number' || isNaN(num)) {
   127→        return { valid: false, error: 'Value must be a valid number' };
   128→      }
   129→      return { valid: true };
   130→
   131→    case 'date':
   132→      // Accept Date objects or ISO date strings
   133→      if (value instanceof Date) {
   134→        if (isNaN(value.getTime())) {
   135→          return { valid: false, error: 'Invalid date' };
   136→        }
   137→        return { valid: true };
   138→      }
   139→      if (typeof value === 'string') {
   140→        const parsed = new Date(value);
   141→        if (isNaN(parsed.getTime())) {
   142→          return { valid: false, error: 'Invalid date format' };
   143→        }
   144→        return { valid: true };
   145→      }
