   246→    if (!selectedFolderId) return;
   247→
   248→    // Save folder and notes for undo
   249→    const folderToDelete = foldersObj[selectedFolderId];
   250→    if (!folderToDelete) {
   251→      log.warn('Folder not found', { folderId: selectedFolderId });
   252→      return;
   253→    }
   254→
   255→    const notesToDelete = Object.values(notesObj).filter(note => note.folderId === selectedFolderId);
   256→    const noteCount = notesToDelete.length;
   257→
   258→    // Delete all notes in this folder (without undo since folder undo will handle it)
