   272→    deleteFolder(selectedFolderId);
   273→
   274→    log.info(`Folder "${folderToDelete.name}" deleted`, { noteCount });
   275→
   276→    // Add undo action to restore folder AND notes
   277→    useUndoStore.getState().addUndoAction(
   278→      `Folder "${folderToDelete.name}" and ${noteCount} note(s) deleted`,
   279→      () => {
   280→        // Restore the folder
   281→        useFoldersStore.setState((state) => ({
   282→          folders: {
   283→            ...state.folders,
   284→            [folderToDelete.id]: folderToDelete,
   285→          },
   286→        }));
   287→
   288→        // Restore all notes
   289→        useNotesStore.setState((state) => {
   290→          const restoredNotes = { ...state.notes };
   291→          notesToDelete.forEach(note => {
   292→            restoredNotes[note.id] = note;
   293→          });
   294→          return {
   295→            notes: restoredNotes,
   296→          };
   297→        });
   298→
   299→        log.info(`Folder "${folderToDelete.name}" and ${noteCount} note(s) restored (undo)`);
   300→      }

