        </div>
      </div>

      {/* Color Grid */}
      <div>
        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
          Select Color
        </label>
        <div className="grid grid-cols-4 gap-2">
          {/* No Color Option */}
          <button
            onClick={() => onColorSelect('')}
            className={`
              relative h-10 rounded border-2 transition-all
              bg-surface-light-elevated dark:bg-surface-dark-elevated
              ${
                !selectedColor
                  ? 'border-accent-purple dark:border-accent-cyan'
                  : 'border-border-light dark:border-border-dark hover:border-accent-purple/50 dark:hover:border-accent-cyan/50'
              }
            `}
            title="No color"
          >
            <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">None</span>
            {!selectedColor && (
              <Check className="absolute top-1 right-1 w-3 h-3 text-accent-purple dark:text-accent-cyan" />
            )}
          </button>

          {/* Color Options */}
          {TAG_COLORS.map((color) => (
            <button
              key={color.name}
              onClick={() => onColorSelect(color.token)}
              className={`
                relative h-10 rounded border-2 transition-all
                bg-${color.token} bg-opacity-20 dark:bg-opacity-30
                ${
                  selectedColor === color.token
                    ? 'border-accent-purple dark:border-accent-cyan'
                    : 'border-border-light dark:border-border-dark hover:border-accent-purple/50 dark:hover:border-accent-cyan/50'
                }
              `}
              title={color.displayName}
            >
              {selectedColor === color.token && (
                <Check className="absolute top-1 right-1 w-3 h-3 text-accent-purple dark:text-accent-cyan" />
              )}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

