/**
 * TagPicker Component
 *
 * Inline tag picker with autocomplete for adding tags to notes
 * Features:
 * - Dropdown with existing tags
 * - Create new tags inline
 * - Keyboard navigation
 * - Click-outside-to-close
 */

import { useState, useRef, useEffect, useMemo } from 'react';
import { X, Plus, Tag as TagIcon, ChevronRight, ChevronDown } from 'lucide-react';
import { useTags, useRecentTags } from '../hooks/useTags';
import { buildTagTree, normalizeTag, type TagNode } from '../utils/tagHierarchy';
import { useSettingsStore } from '../stores/useSettingsStore';

interface TagPickerProps {
  /** Currently selected tags */
  selectedTags: string[];
  /** Callback when tag is added */
  onAddTag: (tag: string) => void;
  /** Callback when tag is removed */
  onRemoveTag: (tag: string) => void;
  /** Maximum number of tags allowed */
  maxTags?: number;
}

export function TagPicker({ selectedTags, onAddTag, onRemoveTag, maxTags = 20 }: TagPickerProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [expandedTags, setExpandedTags] = useState<Set<string>>(new Set());
  const inputRef = useRef<HTMLInputElement>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Get all existing tags and recent tags
  const allTags = useTags();
  const recentTags = useRecentTags(5);
  const tagColors = useSettingsStore((state) => state.tagColors);

  // Build tag tree from all tags
  const tagTree = useMemo(() => buildTagTree(allTags), [allTags]);

  // Filter tags based on search query and exclude already selected
  const filteredTags = allTags.filter(
    (tag) =>
      !selectedTags.includes(tag) &&
      tag.toLowerCase().includes(searchQuery.toLowerCase())
  );

  // Show recent tags if no search query
  const suggestedTags = searchQuery
    ? filteredTags.slice(0, 10)
    : recentTags.filter((tag) => !selectedTags.includes(tag));

  // Handle click outside to close
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (
        dropdownRef.current &&
        !dropdownRef.current.contains(event.target as Node) &&
        inputRef.current &&
        !inputRef.current.contains(event.target as Node)
      ) {
        setIsOpen(false);
        setSearchQuery('');
      }
    }

    if (isOpen) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
    }
  }, [isOpen]);

  // Focus input when opened
  useEffect(() => {
    if (isOpen && inputRef.current) {
      inputRef.current.focus();
    }
  }, [isOpen]);

  const handleAddTag = (tag: string) => {
    const normalizedTag = normalizeTag(tag);
    if (!normalizedTag) return;
    if (selectedTags.includes(normalizedTag)) return;
    if (selectedTags.length >= maxTags) return;

    onAddTag(normalizedTag);
    setSearchQuery('');
    setIsOpen(false);
  };

  const toggleExpand = (tag: string) => {
    setExpandedTags(prev => {
      const next = new Set(prev);
      if (next.has(tag)) {
        next.delete(tag);
      } else {
        next.add(tag);
      }
      return next;
    });
  };

  // Recursive function to render tag tree
  const renderTagNode = (node: TagNode): React.ReactNode => {
    const hasChildren = node.children.length > 0;
    const isExpanded = expandedTags.has(node.name);
    const isSelected = selectedTags.includes(node.name);

    return (
      <div key={node.name}>
        <button
          onClick={() => {
            if (!hasChildren) {
              handleAddTag(node.name);
            }
          }}
          disabled={isSelected}
          className={`
            w-full flex items-center gap-2 px-3 py-1.5 text-sm text-left
            hover:bg-surface-light dark:hover:bg-surface-dark transition-colors
            ${isSelected ? 'opacity-50 cursor-not-allowed' : ''}
          `}
          style={{ paddingLeft: `${node.level * 16 + 12}px` }}
        >
          {hasChildren && (
            <span
              onClick={(e) => {
                e.stopPropagation();
                toggleExpand(node.name);
              }}
              className="flex-shrink-0 cursor-pointer"
            >
              {isExpanded ? (
                <ChevronDown className="w-3 h-3 text-text-light-tertiary dark:text-text-dark-tertiary" />
              ) : (
                <ChevronRight className="w-3 h-3 text-text-light-tertiary dark:text-text-dark-tertiary" />
              )}
            </span>
          )}
          {!hasChildren && <span className="w-3" />}
          <TagIcon className="w-3 h-3 text-accent-purple dark:text-accent-cyan flex-shrink-0" />
          <span className="flex-1 text-text-light-primary dark:text-text-dark-primary truncate">
            {node.label}
          </span>
          {hasChildren && (
            <span className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary flex-shrink-0">
              ({node.children.length})
            </span>
          )}
        </button>

        {/* Render children if expanded */}
        {hasChildren && isExpanded && (
          <div>
            {node.children.map(child => renderTagNode(child))}
          </div>
        )}
      </div>
    );
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      if (searchQuery.trim()) {
        handleAddTag(searchQuery);
      } else if (suggestedTags.length > 0) {
        handleAddTag(suggestedTags[0]);
      }
    } else if (e.key === 'Escape') {
      setIsOpen(false);
      setSearchQuery('');
    }
  };

  const canAddMore = selectedTags.length < maxTags;

  return (
    <div className="relative">
      {/* Selected Tags Display */}
      <div className="flex flex-wrap gap-2 items-center">
        {selectedTags.map((tag) => (
          <span
            key={tag}
            className="inline-flex items-center gap-1 px-2 py-1 text-xs font-medium rounded bg-accent-purple/10 text-accent-purple dark:bg-accent-cyan/10 dark:text-accent-cyan transition-colors"
          >
            <TagIcon className="w-3 h-3" />
            {tag}
            <button
              onClick={() => onRemoveTag(tag)}
              className="hover:bg-accent-purple/20 dark:hover:bg-accent-cyan/20 rounded p-0.5 transition-colors"
              aria-label={`Remove tag ${tag}`}
            >
              <X className="w-3 h-3" />
            </button>
          </span>
        ))}

        {/* Add Tag Button */}
        {canAddMore && (
          <button
            onClick={() => setIsOpen(!isOpen)}
            className="inline-flex items-center gap-1 px-2 py-1 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary transition-colors"
            aria-label="Add tag"
          >
            <Plus className="w-3 h-3" />
            Add tag
          </button>
        )}
      </div>

      {/* Tag Picker Dropdown */}
      {isOpen && (
        <div
          ref={dropdownRef}
          className="absolute z-50 mt-2 w-64 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg shadow-lg"
        >
          {/* Search Input */}
          <div className="p-2 border-b border-border-light dark:border-border-dark">
            <input
              ref={inputRef}
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="Search or create tag..."
              className="w-full px-3 py-2 text-sm bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded focus:outline-none focus:ring-2 focus:ring-accent-purple dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
            />
          </div>

          {/* Tag Suggestions */}
          <div className="max-h-64 overflow-y-auto">
            {searchQuery ? (
              /* Flat filtered list when searching */
              <>
                {!filteredTags.includes(searchQuery) && (
                  <button
                    onClick={() => handleAddTag(searchQuery)}
                    className="w-full px-3 py-2 text-left text-sm hover:bg-surface-light dark:hover:bg-surface-dark transition-colors text-text-light-primary dark:text-text-dark-primary"
                  >
                    <div className="flex items-center gap-2">
                      <Plus className="w-4 h-4 text-accent-purple dark:text-accent-cyan" />
                      <span>
                        Create "<span className="font-medium">{searchQuery}</span>"
                      </span>
                    </div>
                  </button>
                )}

                {filteredTags.length > 0 ? (
                  filteredTags.slice(0, 10).map((tag) => (
                    <button
                      key={tag}
                      onClick={() => handleAddTag(tag)}
                      className="w-full px-3 py-2 text-left text-sm hover:bg-surface-light dark:hover:bg-surface-dark transition-colors text-text-light-primary dark:text-text-dark-primary"
                    >
                      <div className="flex items-center gap-2">
                        <TagIcon className="w-4 h-4 text-accent-purple dark:text-accent-cyan" />
                        {tag}
                      </div>
                    </button>
                  ))
                ) : (
                  <div className="px-3 py-4 text-center text-sm text-text-light-secondary dark:text-text-dark-secondary">
                    No matching tags
                  </div>
                )}
              </>
            ) : (
              /* Hierarchical tree when not searching */
              <>
                {tagTree.length > 0 ? (
                  <div className="py-1">
                    {tagTree.map(node => renderTagNode(node))}
                  </div>
                ) : (
                  <div className="px-3 py-4 text-center text-sm text-text-light-secondary dark:text-text-dark-secondary">
                    No tags yet
                  </div>
                )}
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

input.content:
/**
 * Tag Suggestions Utility
 *
 * Generates smart tag suggestions based on:
 * - Content analysis (keyword extraction)
 * - Frequency (most-used tags)
 * - Co-occurrence (tags often used together)
 * - Hierarchical (child tags when parent selected)
 * - Recent tags (recently used)
 */

import type { Note, TagSuggestion } from '../types/notes';

/**
 * Extract keywords from content for content-based suggestions
 * Simple algorithm: find common words (>3 chars) that appear in tags
 */
function extractKeywords(content: string, allTags: string[]): string[] {
  const normalized = content.toLowerCase();
  const keywords: string[] = [];

  // Check if any tag (or part of hierarchical tag) appears in content
  allTags.forEach(tag => {
    const tagParts = tag.toLowerCase().split('/');
    tagParts.forEach(part => {
      if (part.length > 2 && normalized.includes(part)) {
        keywords.push(tag);
      }
    });
  });

  return keywords;
}

/**
 * Get most frequently used tags across all notes
 */
function getMostFrequentTags(notes: Note[], limit: number): string[] {
  const tagCounts = new Map<string, number>();

  notes.forEach(note => {
    if (!note.isArchived) {
      note.tags.forEach(tag => {
        tagCounts.set(tag, (tagCounts.get(tag) || 0) + 1);
      });
    }
  });

  return Array.from(tagCounts.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, limit)
    .map(([tag]) => tag);
}

/**
 * Find tags that are frequently used together with existing tags
 */
function getCoOccurringTags(existingTags: string[], notes: Note[]): Map<string, number> {
  const coOccurrence = new Map<string, number>();

  notes.forEach(note => {
    if (note.isArchived) return;

    // Check if note has any of the existing tags
    const hasExistingTag = existingTags.some(tag => note.tags.includes(tag));
    if (!hasExistingTag) return;

    // Count other tags in this note
    note.tags.forEach(tag => {
      if (!existingTags.includes(tag)) {
        coOccurrence.set(tag, (coOccurrence.get(tag) || 0) + 1);
      }
    });
  });

  return coOccurrence;
}

/**
 * Get child tags when parent tag is selected
 */
function getHierarchicalSuggestions(existingTags: string[], allTags: string[]): string[] {
  const suggestions: string[] = [];

  existingTags.forEach(parentTag => {
    const prefix = parentTag + '/';
    allTags.forEach(tag => {
      if (tag.startsWith(prefix) && !existingTags.includes(tag)) {
        suggestions.push(tag);
      }
    });
  });

  return suggestions;
}

/**
 * Get recently used tags from latest notes
 */
function getRecentTags(notes: Note[], limit: number, excludeTags: string[]): string[] {
  const recentTags: string[] = [];
  const tagSet = new Set<string>(excludeTags);

  // Sort notes by updatedAt descending
  const sortedNotes = [...notes]
    .filter(note => !note.isArchived)
    .sort((a, b) => b.updatedAt.getTime() - a.updatedAt.getTime());

  // Collect tags from most recent notes
  for (const note of sortedNotes) {
    for (const tag of note.tags) {
      if (!tagSet.has(tag)) {
        tagSet.add(tag);
        recentTags.push(tag);
        if (recentTags.length >= limit) {
          return recentTags;
        }
      }
    }
  }

  return recentTags;
}

/**
 * Generate tag suggestions for a note
 *
 * @param content - Note content (plain text)
 * @param existingTags - Tags already applied to this note
 * @param allNotes - All notes in the system
 * @param maxSuggestions - Maximum number of suggestions to return
 * @returns Sorted array of tag suggestions with scores
 */
export function generateTagSuggestions(
  content: string,
  existingTags: string[],
  allNotes: Note[],
  maxSuggestions = 5
): TagSuggestion[] {
  const suggestions = new Map<string, TagSuggestion>();
  const allTags = Array.from(new Set(allNotes.flatMap(note => note.tags)));

  // 1. Content-based suggestions (highest weight)
  const contentKeywords = extractKeywords(content, allTags);
  contentKeywords.forEach(tag => {
    if (!existingTags.includes(tag)) {
      suggestions.set(tag, {
        tag,
        score: 10,
        reason: 'content',
      });
    }
  });

  // 2. Hierarchical suggestions (high weight if parent selected)
  const hierarchicalTags = getHierarchicalSuggestions(existingTags, allTags);
  hierarchicalTags.forEach(tag => {
    const existing = suggestions.get(tag);
    if (existing) {
      existing.score += 8;
    } else {
      suggestions.set(tag, {
        tag,
        score: 8,
        reason: 'hierarchical',
      });
    }
  });

  // 3. Co-occurrence suggestions (medium weight)
  if (existingTags.length > 0) {
    const coOccurring = getCoOccurringTags(existingTags, allNotes);
    coOccurring.forEach((count, tag) => {
      const existing = suggestions.get(tag);
      const score = Math.min(count, 6); // Cap at 6 points
      if (existing) {
        existing.score += score;
      } else {
        suggestions.set(tag, {
          tag,
          score,
          reason: 'co-occurrence',
        });
      }
    });
  }

  // 4. Frequency suggestions (low weight)
  const frequentTags = getMostFrequentTags(allNotes, 10);
  frequentTags.forEach((tag, index) => {
    if (!existingTags.includes(tag)) {
      const existing = suggestions.get(tag);
      const score = Math.max(1, 5 - index); // 5 points for most frequent, decreasing
      if (existing) {
        existing.score += score;
      } else {
        suggestions.set(tag, {
          tag,
          score,
          reason: 'frequency',
        });
      }
    }
  });

  // 5. Recent tags (lowest weight, fallback)
  const recentTags = getRecentTags(allNotes, 5, existingTags);
  recentTags.forEach(tag => {
    const existing = suggestions.get(tag);
    if (existing) {
      existing.score += 2;
    } else {
      suggestions.set(tag, {
        tag,
        score: 2,
        reason: 'recent',
      });
    }
  });

  // Sort by score descending and return top N
  return Array.from(suggestions.values())
    .sort((a, b) => b.score - a.score)
    .slice(0, maxSuggestions);
}

/**
 * Get user-friendly reason label for suggestion
 */
export function getSuggestionReasonLabel(reason: TagSuggestion['reason']): string {
  switch (reason) {
    case 'content':
      return 'Matches content';
    case 'frequency':
      return 'Frequently used';
    case 'co-occurrence':
      return 'Often used together';
    case 'hierarchical':
      return 'Related tag';
    case 'recent':
      return 'Recently used';
    default:
      return 'Suggested';
  }
}

